/**
 * Dry-run / apply fix for party guests whose directory numbers don't match kiosk.
 *
 * Requires citizen_number to be GENERATED BY DEFAULT — run the SQL preamble
 * from scripts/fix-party-citizen-numbers.sql in Supabase first, or use that
 * SQL file directly (recommended).
 *
 * Usage:
 *   node scripts/fix-party-citizen-numbers.mjs          # dry run
 *   node scripts/fix-party-citizen-numbers.mjs --apply  # update via API
 */

import { createClient } from '@supabase/supabase-js'
import { readFileSync } from 'fs'
import { dirname, join } from 'path'
import { fileURLToPath } from 'url'

const __dirname = dirname(fileURLToPath(import.meta.url))
const apply = process.argv.includes('--apply')

const envPath = join(__dirname, '..', '.env.local')
for (const line of readFileSync(envPath, 'utf8').split('\n')) {
  const trimmed = line.trim()
  if (!trimmed || trimmed.startsWith('#')) continue
  const [key, ...rest] = trimmed.split('=')
  if (key && rest.length) process.env[key] = rest.join('=')
}

const supabase = createClient(
  process.env.NEXT_PUBLIC_SUPABASE_URL,
  process.env.SUPABASE_SERVICE_ROLE_KEY,
)

function matchCitizen(partyRow, citizens) {
  return citizens.find(
    (c) =>
      (c.photo_url &&
        partyRow.photo_url &&
        c.photo_url === partyRow.photo_url) ||
      (!c.photo_url &&
        !partyRow.photo_url &&
        c.name === partyRow.name &&
        c.relation_to_tomo === partyRow.relation_to_tomo),
  )
}

async function main() {
  const { data: party, error: partyError } = await supabase
    .from('party_citizens')
    .select('id, citizen_number, tomoland_id, name, relation_to_tomo, photo_url')
    .order('citizen_number', { ascending: true })

  if (partyError) {
    console.error('Failed to fetch party_citizens:', partyError.message)
    process.exit(1)
  }

  const { data: citizens, error: citizensError } = await supabase
    .from('citizens')
    .select('id, citizen_number, tomoland_id, name, relation_to_tomo, photo_url')

  if (citizensError) {
    console.error('Failed to fetch citizens:', citizensError.message)
    process.exit(1)
  }

  const fixes = []
  const missing = []

  for (const guest of party) {
    const row = matchCitizen(guest, citizens)
    if (!row) {
      missing.push(guest)
      continue
    }
    if (row.citizen_number !== guest.citizen_number) {
      fixes.push({ guest, row })
    }
  }

  console.log(`Party guests: ${party.length}`)
  console.log(`Need renumbering: ${fixes.length}`)
  console.log(`Missing from citizens: ${missing.length}\n`)

  for (const { guest, row } of fixes) {
    console.log(
      `  ${guest.tomoland_id} ${guest.name} — directory ${row.tomoland_id} -> ${guest.tomoland_id}`,
    )
  }

  if (!apply) {
    if (fixes.length) {
      console.log(
        '\nRecommended: run scripts/fix-party-citizen-numbers.sql in Supabase SQL Editor.',
      )
      console.log('Or re-run with --apply after the SQL ALTER preamble (BY DEFAULT).')
    }
    return
  }

  if (!fixes.length) {
    console.log('\nNothing to update.')
    return
  }

  let updated = 0
  let failed = 0

  for (const { guest, row } of fixes) {
    const { data, error } = await supabase
      .from('citizens')
      .update({ citizen_number: guest.citizen_number })
      .eq('id', row.id)
      .select('tomoland_id')
      .single()

    if (error) {
      console.error(`  ❌ ${guest.name}: ${error.message}`)
      failed++
      if (error.message.includes('cannot insert a non-DEFAULT value')) {
        console.error(
          '\nRun scripts/fix-party-citizen-numbers.sql in Supabase SQL Editor instead.',
        )
        process.exit(1)
      }
      continue
    }

    console.log(`  ✅ ${guest.name} -> ${data.tomoland_id}`)
    updated++
    await new Promise((r) => setTimeout(r, 50))
  }

  console.log(`\nDone: ${updated} updated, ${failed} failed`)
}

main().catch(console.error)
